/// Domain-typed [`kyoso_graph::scene::Scene`] for the kyoso_core
/// scene model:
/// `Scene<&SceneNode, &SceneEdge, With<SceneNode>>`.
///
/// Convenience alias for in-system reads that want both the scene
/// hierarchy and the entity-edge graph **filtered to entities
/// carrying the [`SceneNode`] marker**. The `With<SceneNode>` filter
/// is shared by both inner queries ‚Äî non-`SceneNode` overlays are
/// invisible to both `scene.tree.*` and `scene.graph.*`. Use the
/// agent-facing [`kyoso_graph::traversal::WorldGraphView`] (or
/// [`SceneWorld`]) if you need to see bare overlays too.
pub type SceneView<'w, 's> = kyoso_graph::scene::Scene<
    'w,
    's,
    &'static SceneNode,
    &'static SceneEdge,
    bevy::ecs::query::With<SceneNode>,
>;

// ---------------------------------------------------------------------------
// Structural markers
// ---------------------------------------------------------------------------

/// Zero-sized marker: every kyoso_core node entity carries this. Used
/// as the `N` parameter to [`kyoso_graph_sync::GraphSyncPlugin`] so
/// structural ops (`AddNode`, `RemoveNode`, `Move`) operate on a
/// uniform "this is a scene node" identity, decoupled from which
/// specific node kind (`Frame` / `Rectangle` / `Text` / ...) the
/// entity carries.
#[derive(Component, Default, Clone, Debug, PartialEq, Eq, Reflect)]
#[reflect(Component, Default)]
#[require(kyoso_graph_sync::NodePresence)]
pub struct SceneNode;

/// Discriminator tag: which variant of [`Node`](crate::node::Node) does
/// this entity carry? Inserted atomically with the variant's data via
/// the `*Data` bundles (see [`FrameData`](crate::FrameData) etc.)
/// so the tag and the data cannot drift apart.
#[derive(
    Component, Reflect, Copy, Clone, Debug, PartialEq, Eq, Hash, Serialize, Deserialize,
    schemars::JsonSchema,
)]
#[reflect(Component)]
#[serde(rename_all = "snake_case")]
pub enum NodeKind {
    Frame,
    Rectangle,
    Text,
}

/// Zero-sized marker: every kyoso_core edge entity carries this. The
/// initial cut only uses tree edges (via `kyoso_graph::tree`);
/// reference edges (component‚Üímain, prototype links) are deferred.
#[derive(Component, Default, Clone, Debug, PartialEq, Eq, Reflect)]
#[reflect(Component, Default)]
#[require(kyoso_graph_sync::EdgeEndpoints)]
pub struct SceneEdge;

// ---------------------------------------------------------------------------
// Typed-graph trait impl ‚Äî SceneNode IS the typed graph identifier.
// One `impl Graph for SceneNode` replaces the previous separate
// `TypedGraphNode` + `TypedGraphEdge` impls.
// ---------------------------------------------------------------------------

impl kyoso_graph::Graph for SceneNode {
    // Nodes
    type NodeMarker = SceneNode;
    type Node = crate::node::Node;
    type NodeData = crate::query_data::AnyNodeQueryData;
    type NodeDiscriminator = NodeKind;
    /// The closed family of scene-node variants, in dispatch order.
    /// The `NodeVariants` tuple impl (arity 3) drives
    /// `try_materialize(Entity ‚Üí Node)` over `&World` directly ‚Äî used
    /// by the agent-facing traversal layer in `crate::traversal`.
    /// Adding a fourth kind = a new `NodeVariant` impl + one entry here.
    type Variants = (Frame, Rectangle, Text);
    // Edges ‚Äî no typed edges yet; `()` is the empty-edge-variant shape.
    type EdgeMarker = SceneEdge;
    type Edge = ();
    type EdgeData = ();
    type EdgeDiscriminator = ();
}
